"""
Ativos gráficos embutidos em base64 (extraídos do modelo oficial de Declaração
do PPGEduc/UFBA): brasão da UFBA, logomarca do PGED e assinatura do
coordenador. Mantidos aqui para que o app funcione como um único arquivo,
sem depender de imagens externas.
"""

SHIELD_UFBA_B64 = ""

LOGO_PGED_B64 = ""

ASSINATURA_COORD_B64 = ""
import base64
import io
import re
import zipfile

import streamlit as st
import pdfplumber
from docx import Document
from docx.shared import Pt, Cm
from docx.enum.text import WD_ALIGN_PARAGRAPH
from docx.enum.table import WD_TABLE_ALIGNMENT, WD_ALIGN_VERTICAL
from docx.oxml.ns import qn
from docx.oxml import OxmlElement


# ============================================================
# UTILITÁRIOS DE FORMATAÇÃO DO DOCX (cabeçalho, fonte, assinatura)
# ============================================================

def _remover_bordas_tabela(table):
    tbl_pr = table._tbl.tblPr
    borders = OxmlElement('w:tblBorders')
    for lado in ('top', 'left', 'bottom', 'right', 'insideH', 'insideV'):
        el = OxmlElement(f'w:{lado}')
        el.set(qn('w:val'), 'nil')
        borders.append(el)
    tbl_pr.append(borders)


def _imagem_de_base64(b64_str):
    return io.BytesIO(base64.b64decode(b64_str))


def _novo_documento_base():
    """Cria um documento com margens e fonte padrão já configuradas."""
    doc = Document()
    for section in doc.sections:
        section.top_margin = Cm(2.5)
        section.bottom_margin = Cm(2.2)
        section.left_margin = Cm(2.8)
        section.right_margin = Cm(2.8)

    normal = doc.styles['Normal']
    normal.font.name = 'Times New Roman'
    normal.font.size = Pt(12)
    rpr = normal.element.get_or_add_rPr()
    rFonts = rpr.find(qn('w:rFonts'))
    if rFonts is None:
        rFonts = OxmlElement('w:rFonts')
        rpr.append(rFonts)
    rFonts.set(qn('w:eastAsia'), 'Times New Roman')
    return doc


def _adicionar_cabecalho(doc):
    """Brasão da UFBA | texto do programa | logo do PGED, sem bordas."""
    tabela = doc.add_table(rows=1, cols=3)
    tabela.alignment = WD_TABLE_ALIGNMENT.CENTER
    larguras = [Cm(2.3), Cm(11.5), Cm(2.3)]
    for i, w in enumerate(larguras):
        tabela.columns[i].width = w
        tabela.rows[0].cells[i].width = w
    _remover_bordas_tabela(tabela)

    cel_brasao, cel_texto, cel_logo = tabela.rows[0].cells
    for cel in (cel_brasao, cel_texto, cel_logo):
        cel.vertical_alignment = WD_ALIGN_VERTICAL.CENTER

    p_brasao = cel_brasao.paragraphs[0]
    p_brasao.alignment = WD_ALIGN_PARAGRAPH.CENTER
    p_brasao.add_run().add_picture(_imagem_de_base64(SHIELD_UFBA_B64), height=Cm(2.0))

    p1 = cel_texto.paragraphs[0]
    p1.alignment = WD_ALIGN_PARAGRAPH.CENTER
    p1.add_run("UNIVERSIDADE FEDERAL DA BAHIA - FACULDADE DE EDUCAÇÃO")
    p2 = cel_texto.add_paragraph()
    p2.alignment = WD_ALIGN_PARAGRAPH.CENTER
    p2.add_run("Programa de Pós-Graduação em Educação – Mestrado e Doutorado")

    p_logo = cel_logo.paragraphs[0]
    p_logo.alignment = WD_ALIGN_PARAGRAPH.CENTER
    p_logo.add_run().add_picture(_imagem_de_base64(LOGO_PGED_B64), height=Cm(1.8))

    doc.add_paragraph()
    doc.add_paragraph()


def _adicionar_titulo(doc, texto="D E C L A R A Ç Ã O"):
    titulo = doc.add_paragraph()
    titulo.alignment = WD_ALIGN_PARAGRAPH.CENTER
    run_titulo = titulo.add_run(texto)
    run_titulo.bold = True
    run_titulo.font.size = Pt(16)
    doc.add_paragraph()


def _adicionar_rodape_assinatura(doc, data_emissao, coordenador, coordenador_cargo):
    doc.add_paragraph()
    doc.add_paragraph()

    data_p = doc.add_paragraph()
    data_p.alignment = WD_ALIGN_PARAGRAPH.CENTER
    data_p.add_run(data_emissao)

    doc.add_paragraph()

    p_assinatura_img = doc.add_paragraph()
    p_assinatura_img.alignment = WD_ALIGN_PARAGRAPH.CENTER
    p_assinatura_img.add_run().add_picture(
        _imagem_de_base64(ASSINATURA_COORD_B64), height=Cm(1.6)
    )

    p_nome_coord = doc.add_paragraph()
    p_nome_coord.alignment = WD_ALIGN_PARAGRAPH.CENTER
    p_nome_coord.add_run(coordenador).bold = True

    p_cargo_coord = doc.add_paragraph()
    p_cargo_coord.alignment = WD_ALIGN_PARAGRAPH.CENTER
    p_cargo_coord.add_run(coordenador_cargo)


def _finalizar(doc):
    buffer = io.BytesIO()
    doc.save(buffer)
    buffer.seek(0)
    return buffer


# ============================================================
# GERAÇÃO DA DECLARAÇÃO DA(O) DISCENTE (documento único)
# ============================================================

def gerar_declaracao_discente_docx(dados):
    doc = _novo_documento_base()
    _adicionar_cabecalho(doc)
    _adicionar_titulo(doc)

    corpo = doc.add_paragraph()
    corpo.alignment = WD_ALIGN_PARAGRAPH.JUSTIFY
    corpo.paragraph_format.line_spacing = 1.15
    corpo.add_run("Declaramos, para os devidos fins, que ")
    corpo.add_run(dados["nome_discente"]).bold = True
    corpo.add_run(f" realizou exame de Qualificação do Projeto de {dados['tipo_trabalho']} intitulado \u201c")
    corpo.add_run(dados["titulo_projeto"]).bold = True
    corpo.add_run(f"\u201d, em {dados['data_exame']}, sob a orientação da(o) ")
    corpo.add_run(dados["orientador_titulo"])
    corpo.add_run(" ")
    corpo.add_run(dados["orientador_nome"]).bold = True
    corpo.add_run(".")

    doc.add_paragraph()

    banca = doc.add_paragraph()
    banca.alignment = WD_ALIGN_PARAGRAPH.JUSTIFY
    banca.paragraph_format.line_spacing = 1.15
    banca.add_run(
        "Integraram ainda como membros titulares da banca examinadora os(as) "
        "Professores(as) Doutores(as) "
    )
    banca.add_run(dados["membros_banca_texto"])
    banca.add_run(".")

    _adicionar_rodape_assinatura(
        doc, dados["data_emissao"], dados["coordenador"], dados["coordenador_cargo"]
    )
    return _finalizar(doc)


# ============================================================
# GERAÇÃO DE DECLARAÇÃO INDIVIDUAL POR PARTICIPANTE DA BANCA
# ============================================================

def gerar_declaracao_individual_docx(dados_gerais, participante):
    """participante: dict com nome, instituicao, titulo, papel
    (papel = 'Orientador(a)' ou 'Membro Titular')."""

    doc = _novo_documento_base()
    _adicionar_cabecalho(doc)
    _adicionar_titulo(doc)

    corpo = doc.add_paragraph()
    corpo.alignment = WD_ALIGN_PARAGRAPH.JUSTIFY
    corpo.paragraph_format.line_spacing = 1.15
    corpo.add_run("Declaramos, para os devidos fins, que ")
    nome_run = corpo.add_run(f"{participante['titulo']} {participante['nome']}")
    nome_run.bold = True
    if participante.get("instituicao"):
        corpo.add_run(f" ({participante['instituicao']})")

    if participante["papel"] == "Orientador(a)":
        corpo.add_run(" atuou como orientador(a) e participou, na qualidade de membro, da banca examinadora")
    else:
        corpo.add_run(" participou como membro titular da banca examinadora")

    corpo.add_run(
        f" do exame de Qualificação do Projeto de {dados_gerais['tipo_trabalho']} de "
    )
    corpo.add_run(dados_gerais["nome_discente"]).bold = True
    corpo.add_run(", intitulado \u201c")
    corpo.add_run(dados_gerais["titulo_projeto"]).bold = True
    corpo.add_run(f"\u201d, realizado em {dados_gerais['data_exame']}.")

    _adicionar_rodape_assinatura(
        doc,
        dados_gerais["data_emissao"],
        dados_gerais["coordenador"],
        dados_gerais["coordenador_cargo"],
    )
    return _finalizar(doc)


# ============================================================
# EXTRAÇÃO DE DADOS A PARTIR DO PDF DA ATA DE BANCA
# ============================================================

def extrair_texto_pdf(arquivo):
    texto = ""
    try:
        with pdfplumber.open(arquivo) as pdf:
            for pagina in pdf.pages:
                texto += (pagina.extract_text() or "") + "\n"
    except Exception:
        return ""
    return texto


def extrair_dados_da_ata(texto):
    """Extrai os dados de uma Ata de Banca de Qualificação (PPGEduc/UFBA).
    Campos não encontrados retornam vazios/listas vazias para edição manual."""

    dados = {
        "nome_discente": "",
        "curso": "",
        "tipo_trabalho": "",
        "titulo_projeto": "",
        "data_exame": "",
        "orientador_nome": "",
        "orientador_titulo": "Professor(a) Doutor(a)",
        "banca": [],  # lista de {"nome":..., "instituicao":...}
    }

    if not texto:
        return dados

    t = re.sub(r"\s+", " ", texto).strip()

    m = re.search(r"CURSO DE (DOUTORADO|MESTRADO)", t, re.IGNORECASE)
    if m:
        dados["curso"] = m.group(1).capitalize()

    m = re.search(r"Trabalho de Qualifica[çc][ãa]o de (Tese|Disserta[çc][ãa]o)", t, re.IGNORECASE)
    if m:
        dados["tipo_trabalho"] = m.group(1).capitalize()

    m = re.search(r"ACAD[ÊE]MIC[OA]:\s*([^\n]+)", texto)
    if m:
        dados["nome_discente"] = m.group(1).strip()

    m = re.search(r'intitulad[oa]\s*["“]\s*(.+?)\s*["”]', t, re.IGNORECASE)
    if m:
        dados["titulo_projeto"] = m.group(1).strip()

    m = re.search(r"Salvador,?\s*(\d{1,2}\s+de\s+\w+\s+de\s+\d{4})", t, re.IGNORECASE)
    if m:
        dados["data_exame"] = m.group(1)

    # Segmento que lista a comissão avaliadora (entre "composta pel..." e "para avaliar")
    m = re.search(r"[Cc]omiss[ãa]o [Aa]valiadora composta pel[a-zà-ú]*\s*(.+?)\s*para avaliar", t)
    segmento = m.group(1) if m else ""

    m = re.search(r"por mim,\s*([A-ZÀ-Ú][\wÀ-ú'\.\-\s]+?)\s*-\s*(orientador[a]?)", t, re.IGNORECASE)
    if m:
        dados["orientador_nome"] = m.group(1).strip()
        dados["orientador_titulo"] = (
            "Professora Doutora" if m.group(2).lower() == "orientadora" else "Professor Doutor"
        )

    pares = re.findall(r"([A-ZÀ-Ú][\wÀ-ú'\.\-\s]+?)\s*\(([^)]+)\)", segmento)
    dados["banca"] = [{"nome": nome.strip(), "instituicao": instit.strip()} for nome, instit in pares]

    return dados


# ============================================================
# INTERFACE (STREAMLIT)
# ============================================================

st.set_page_config(page_title="Gerador de Declarações — PPGEduc/UFBA", page_icon="📄")

st.title("Gerador de Declarações de Qualificação")
st.caption("Programa de Pós-Graduação em Educação (PPGEduc) — UFBA")
st.subheader("Anexe a Ata de Banca para extrair as informações")

arquivo_ata = st.file_uploader("Anexe a Ata de Banca de Qualificação (PDF)", type=["pdf"])

extraidos = {
    "nome_discente": "",
    "curso": "Doutorado",
    "tipo_trabalho": "Tese",
    "titulo_projeto": "",
    "data_exame": "",
    "orientador_nome": "",
    "orientador_titulo": "Professor(a) Doutor(a)",
    "banca": [],
}

if arquivo_ata is not None:
    texto_extraido = extrair_texto_pdf(arquivo_ata)
    if texto_extraido:
        encontrados = extrair_dados_da_ata(texto_extraido)
        extraidos.update({k: v for k, v in encontrados.items() if v})
        st.success("Ata anexada e texto lido com sucesso!")
        with st.expander("Ver texto extraído da ata (conferência)"):
            st.text(texto_extraido)
    else:
        st.warning(
            "Não foi possível ler texto da ata (pode ser um PDF digitalizado/escaneado). "
            "Preencha os campos manualmente abaixo."
        )

st.markdown("### Dados gerais (comuns a todas as declarações)")
st.caption("Confira e ajuste os dados extraídos antes de gerar os documentos.")

col1, col2 = st.columns(2)
with col1:
    nome_discente = st.text_input("Nome do(a) Discente", extraidos["nome_discente"])
    tipo_trabalho = st.selectbox(
        "Tipo de Trabalho", ["Tese", "Dissertação"],
        index=0 if extraidos["tipo_trabalho"] != "Dissertação" else 1,
    )
    data_exame = st.text_input("Data do Exame", extraidos["data_exame"])
with col2:
    data_emissao = st.text_input(
        "Cidade e Data de Emissão",
        f"Salvador, {extraidos['data_exame']}" if extraidos["data_exame"] else "Salvador, ",
    )
    coordenador = st.text_input("Nome do(a) Coordenador(a)", "Jonei Cerqueira Barbosa")
    coordenador_cargo = st.selectbox("Cargo", ["Coordenador", "Coordenadora", "Coordenador(a)"])

titulo_projeto = st.text_area("Título do Projeto", extraidos["titulo_projeto"], height=80)

st.markdown("### Orientador(a)")
col3, col4 = st.columns([3, 1])
with col3:
    orientador_nome = st.text_input("Nome do(a) Orientador(a)", extraidos["orientador_nome"])
with col4:
    orientador_titulo = st.selectbox(
        "Título",
        ["Professora Doutora", "Professor Doutor"],
        index=0 if extraidos["orientador_titulo"] != "Professor Doutor" else 1,
        key="orientador_titulo_select",
    )

st.markdown("### Participantes da banca")
st.caption(
    "Lista extraída da ata — ajuste nomes, instituições e títulos, marque quem deve "
    "receber declaração e gere os documentos individuais logo abaixo."
)

linhas_iniciais = [
    {
        "Incluir": True,
        "Papel": "Orientador(a)",
        "Nome": orientador_nome,
        "Instituição": "UFBA",
        "Título": orientador_titulo,
    }
]
for m in extraidos["banca"]:
    linhas_iniciais.append(
        {
            "Incluir": True,
            "Papel": "Membro Titular",
            "Nome": m["nome"],
            "Instituição": m["instituicao"],
            "Título": "Professor(a) Doutor(a)",
        }
    )

participantes_editados = st.data_editor(
    linhas_iniciais,
    num_rows="dynamic",
    use_container_width=True,
    column_config={
        "Papel": st.column_config.SelectboxColumn(
            options=["Orientador(a)", "Membro Titular"]
        ),
        "Título": st.column_config.SelectboxColumn(
            options=["Professora Doutora", "Professor Doutor", "Professor(a) Doutor(a)"]
        ),
        "Incluir": st.column_config.CheckboxColumn(),
    },
    key="tabela_banca",
)

# Texto consolidado dos membros (para a declaração única da/o discente)
nomes_membros = [
    f"{p['Nome']} ({p['Instituição']})" if p["Instituição"] else p["Nome"]
    for p in participantes_editados
    if p["Papel"] == "Membro Titular" and p["Nome"]
]
if len(nomes_membros) > 1:
    membros_banca_texto = ", ".join(nomes_membros[:-1]) + " e " + nomes_membros[-1]
elif nomes_membros:
    membros_banca_texto = nomes_membros[0]
else:
    membros_banca_texto = ""

dados_gerais = {
    "nome_discente": nome_discente,
    "tipo_trabalho": tipo_trabalho,
    "titulo_projeto": titulo_projeto,
    "data_exame": data_exame,
    "data_emissao": data_emissao,
    "orientador_nome": orientador_nome,
    "orientador_titulo": orientador_titulo,
    "membros_banca_texto": membros_banca_texto,
    "coordenador": coordenador,
    "coordenador_cargo": coordenador_cargo,
}

st.divider()

col_a, col_b = st.columns(2)

with col_a:
    st.markdown("#### Declaração única da(o) discente")
    if st.button("Gerar Declaração da(o) Discente (.docx)"):
        obrigatorios = [nome_discente, titulo_projeto, data_exame, orientador_nome]
        if not all(obrigatorios):
            st.error("Preencha nome do(a) discente, título, data do exame e orientador(a).")
        else:
            arquivo_gerado = gerar_declaracao_discente_docx(dados_gerais)
            st.download_button(
                label="⬇️ Baixar Declaração da(o) Discente",
                data=arquivo_gerado,
                file_name=f"Declaracao_{nome_discente.replace(' ', '_')}.docx",
                mime="application/vnd.openxmlformats-officedocument.wordprocessingml.document",
            )

with col_b:
    st.markdown("#### Declarações individuais da banca")
    if st.button("Gerar Declarações Individuais (.zip)", type="primary"):
        obrigatorios = [nome_discente, titulo_projeto, data_exame]
        incluidos = [p for p in participantes_editados if p["Incluir"] and p["Nome"]]
        if not all(obrigatorios):
            st.error("Preencha nome do(a) discente, título e data do exame.")
        elif not incluidos:
            st.error("Marque ao menos um participante na tabela acima.")
        else:
            buffer_zip = io.BytesIO()
            with zipfile.ZipFile(buffer_zip, "w") as zf:
                for p in incluidos:
                    participante = {
                        "nome": p["Nome"],
                        "instituicao": p["Instituição"],
                        "titulo": p["Título"],
                        "papel": p["Papel"],
                    }
                    doc_buf = gerar_declaracao_individual_docx(dados_gerais, participante)
                    nome_arquivo = f"Declaracao_{p['Nome'].replace(' ', '_')}.docx"
                    zf.writestr(nome_arquivo, doc_buf.read())
            buffer_zip.seek(0)
            st.download_button(
                label="⬇️ Baixar Declarações (.zip)",
                data=buffer_zip,
                file_name=f"Declaracoes_Banca_{nome_discente.replace(' ', '_')}.zip",
                mime="application/zip",
            )
